# Caso: Transacción | Nivel: Intermedio | Categoría: Base de datos
# Julia (LibPQ) - ejemplo.
# ] add LibPQ
using LibPQ

function solve()
  conn = LibPQ.Connection(ENV["DATABASE_URL"])
  execute(conn, """BEGIN;
  UPDATE users SET email = 'x@demo.cl' WHERE id = 1;
  -- Si algo falla: ROLLBACK;
COMMIT;""")
  close(conn)
end
